const AgentOrchestrator = require('./agent-orchestrator');

async function processB2BMessage(input, flow, nodeData) {
    try {
        const orchestrator = new AgentOrchestrator({
            dbConnectionString: process.env.DB_CONNECTION_STRING,
            maxConcurrentAgents: parseInt(process.env.MAX_CONCURRENT_AGENTS) || 5,
            agentTimeout: parseInt(process.env.AGENT_TIMEOUT) || 30000
        });

        await orchestrator.initialize();

        const result = await orchestrator.processCustomerMessage({
            phoneNumber: input.phoneNumber || '+5491123456789',
            message: input.message || input.question || input.chatInput,
            flowState: {
                customerType: input.customerType || 'business',
                urgency: input.urgency || 'medium',
                sessionId: input.sessionId
            },
            agentStrategy: input.strategy || 'sequential'
        });

        return {
            response: result.response,
            agentsUsed: result.agentsUsed,
            executionTime: result.executionTime,
            followUpScheduled: result.followUpScheduled
        };
    } catch (error) {
        console.error('Error en orchestrator:', error);
        return {
            response: 'Disculpá, tuve un problema técnico. Un representante te contactará pronto.',
            error: error.message
        };
    }
}

const { B2BSalesDB } = require('./database-config');

async function queryB2BDatabase(input, flow, nodeData) {
    try {
        const db = new B2BSalesDB(process.env.DB_CONNECTION_STRING);
        await db.connect();

        let result;

        switch (input.operation) {
            case 'getCustomer':
                result = await db.getCustomerByPhone(input.phoneNumber);
                break;
            case 'upsertCustomer':
                result = await db.upsertCustomer(input.customerData);
                break;
            case 'createSale':
                result = await db.createSale(input.saleData);
                break;
            case 'scheduleFollowUp':
                result = await db.scheduleFollowUp(input.followUpData);
                break;
            case 'getPendingFollowUps':
                result = await db.getPendingFollowUps();
                break;
            default:
                throw new Error('Operación no válida: ' + input.operation);
        }

        await db.disconnect();
        return result;
    } catch (error) {
        console.error('Error en base de datos:', error);
        throw error;
    }
}

